module RefModule(clk, reset, d, q);  

    input  clk;  
    input  reset;  
    input  d;  
    output  q;  
    reg   q; 
    initial q = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
          begin
            if (reset)
                q <= 0;
            else
                q <= d;
          end  

endmodule
